import type { HookEvent } from '../../types.js';

/**
 * Generate a hook script for a given event type.
 *
 * The generated script is a thin wrapper that imports the VGuard hook runner
 * from node_modules and calls it with the event type.
 */
export function generateHookScript(event: HookEvent): string {
  return `#!/usr/bin/env node
// Generated by VGuard — do not edit manually.
// Regenerate with: npx vguard generate

import { executeHook } from '@anthril/vguard/hooks/runner';

executeHook('${event}');
`;
}
